// SPDX-License-Identifier: MIT
pragma solidity ^0.8.4;

import "@openzeppelin/contracts/security/ReentrancyGuard.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/math/SafeMath.sol";

contract CompoundStakingReward is ReentrancyGuard, Ownable {
    using SafeMath for uint256;

    enum State { Active, Depositing, Withdrawing, Paused, Closed }

    struct UserInfo {
        uint256 shares;
        uint256 lastDepositedTime;
        uint256 rewardDebt;
    }

    IERC20 public stakingToken;
    uint256 public totalShares;
    uint256 public penaltyPeriods;
    uint256 public penaltyRates;
    uint256 public rewardPerShare;
    mapping(address => UserInfo) public userInfo;
    State public state = State.Active;

    event Deposit(address indexed user, uint256 amount);
    event Withdraw(address indexed user, uint256 amount);
    event StateChanged(State newState);

    modifier onlyWhen(State expectedState) {
        require(state == expectedState, "Invalid state");
        _;
    }

    constructor(
        address _stakingToken,
        uint256 _penaltyPeriods,
        uint256 _penaltyRates
    ) {
        require(_stakingToken != address(0), "Invalid token address");
        stakingToken = IERC20(_stakingToken);
        penaltyPeriods = _penaltyPeriods;
        penaltyRates = _penaltyRates;
    }

    function depositFor(address _for, uint256 _amount) external nonReentrant onlyWhen(State.Depositing) {
        require(_amount > 0, "Amount must be greater than zero");
        bool transferSuccess = stakingToken.transferFrom(msg.sender, address(this), _amount);
        require(transferSuccess, "Transfer failed");

        updateReward();
        UserInfo storage user = userInfo[_for];
        if (user.shares == 0) {
            user.lastDepositedTime = block.timestamp;
        }
        uint256 newShares = _amount.mul(totalShares).div(stakingToken.balanceOf(address(this)));
        user.shares = user.shares.add(newShares);
        totalShares = totalShares.add(newShares);
        emit Deposit(_for, _amount);
    }

    function deposit(uint256 _amount) external {
        require(state == State.Active || state == State.Depositing, "Not allowed");
        if (state == State.Active) {
            state = State.Depositing;
        }
        depositFor(msg.sender, _amount);
        if (state == State.Depositing) {
            state = State.Active;
        }
    }

    function withdraw(uint256 _shares) external nonReentrant {
        require(state == State.Active || state == State.Withdrawing, "Not allowed");
        if (state == State.Active) {
            state = State.Withdrawing;
        }
        UserInfo storage user = userInfo[msg.sender];
        require(user.shares >= _shares, "Insufficient shares");

        uint256 penalty = 0;
        if (block.timestamp - user.lastDepositedTime < penaltyPeriods) {
            penalty = _shares.mul(penaltyRates).div(100);
        }

        uint256 amount = _shares.mul(stakingToken.balanceOf(address(this))).div(totalShares);
        if (penalty > 0) {
            amount = amount.sub(penalty);
        }

        user.shares = user.shares.sub(_shares);
        totalShares = totalShares.sub(_shares);
        bool transferSuccess = stakingToken.transfer(msg.sender, amount);
        require(transferSuccess, "Transfer failed");

        if (state == State.Withdrawing) {
            state = State.Active;
        }

        emit Withdraw(msg.sender, amount);
    }

    function calculateSharesValueInState() external view returns (uint256) {
        return userInfo[msg.sender].shares.mul(stakingToken.balanceOf(address(this))).div(totalShares);
    }

    function updateReward() internal {
        uint256 balance = stakingToken.balanceOf(address(this));
        uint256 newReward = balance.sub(totalShares.mul(rewardPerShare));
        rewardPerShare = rewardPerShare.add(newReward.div(totalShares));
    }

    function compoundRewards() external onlyOwner {
        updateReward();
    }

    function changeState(State newState) external onlyOwner {
        state = newState;
        emit StateChanged(newState);
    }
}
