        require(state == State.Active || state == State.Withdrawing, "Not allowed");
        if (state == State.Active) {
            state = State.Withdrawing;
        }
        UserInfo storage user = userInfo[msg.sender];
        require(user.shares >= _shares, "Insufficient shares");

        uint256 penalty = 0;
        if (block.timestamp - user.lastDepositedTime < penaltyPeriods) {
            penalty = (_shares * penaltyRates) / 100;
        }

        uint256 amount = (_shares * stakingToken.balanceOf(address(this))) / totalShares;
        if (penalty > 0) {
            amount -= penalty;
        }

        user.shares -= _shares;
        totalShares -= _shares;
        bool transferSuccess = stakingToken.transfer(msg.sender, amount);
        require(transferSuccess, "Transfer failed");

        if (state == State.Withdrawing) {
            state = State.Active;
        }

        emit Withdraw(msg.sender, amount);
    }

    function calculateSharesValueInState() external view returns (uint256) {
        return (userInfo[msg.sender].shares * stakingToken.balanceOf(address(this))) / totalShares;
    }

    function updateReward() internal {
        uint256 balance = stakingToken.balanceOf(address(this));
        uint256 newReward = balance - (totalShares * rewardPerShare);
        rewardPerShare += newReward / totalShares;
    }

    function compoundRewards() external onlyOwner {
        updateReward();
    }
}
